import { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import API, {
  getApiError,
  IS_DEMO_SEED_ENABLED,
  IS_MOCK_API
} from "../services/api";
import { getDefaultRouteForRole, setSession } from "../services/auth";

const DEMO_EMAILS = new Set([
  "productadmin@pulsefit.com",
  "aarav@ironforge.com"
]);

function normalizeEmail(email) {
  return email.trim().toLowerCase();
}

function normalizePassword(password) {
  return password.trim() === "1234" ? "1234" : password;
}

export default function Login() {
  const navigate = useNavigate();
  const location = useLocation();
  const redirectTo = location.state?.from;
  const [form, setForm] = useState({ email: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [seedLoading, setSeedLoading] = useState(false);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");

  const updateField = (key, value) => {
    setForm((current) => ({ ...current, [key]: value }));
  };

  const completeLogin = (response) => {
    setSession(response.data.token, response.data.user);
    navigate(redirectTo || getDefaultRouteForRole(response.data.user?.role), {
      replace: true
    });
  };

  const handleLogin = async (event) => {
    event.preventDefault();
    setError("");
    setMessage("");
    setLoading(true);

    const credentials = {
      email: normalizeEmail(form.email),
      password: normalizePassword(form.password)
    };
    const isDemoLogin =
      IS_DEMO_SEED_ENABLED &&
      DEMO_EMAILS.has(credentials.email) &&
      credentials.password === "1234";

    try {
      const response = await API.post("/login", credentials);
      completeLogin(response);
    } catch (requestError) {
      if (isDemoLogin) {
        try {
          await API.get("/seed");
          const retryResponse = await API.post("/login", credentials);
          setMessage("Demo data was reset and the demo account signed in successfully.");
          completeLogin(retryResponse);
          return;
        } catch (retryError) {
          setError(getApiError(retryError, "Unable to log in."));
          return;
        }
      }

      setError(getApiError(requestError, "Unable to log in."));
    } finally {
      setLoading(false);
    }
  };

  const handleSeed = async () => {
    setSeedLoading(true);
    setError("");
    setMessage("");

    try {
      await API.get("/seed"); 
      setForm({ email: "productadmin@pulsefit.com", password: "1234" });
      setMessage("Demo users created. You can now sign in with the product admin account.");
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to create the demo users."));
    } finally {
      setSeedLoading(false);
    }
  };

  return (
    <div className="auth-layout">
      <section className="auth-hero">
        <span className="eyebrow">Gym membership manager</span>
        <h1>Run your front desk from one clean workspace.</h1>
        <p>Track members, renewals, and attendance in one place.</p>

        <div className="auth-feature-list">
          <div className="auth-feature">
            <strong>Membership tracking</strong>
            <span>View members and plans quickly.</span>
          </div>
          <div className="auth-feature">
            <strong>Attendance updates</strong>
            <span>Mark check-ins fast.</span>
          </div>
          <div className="auth-feature">
            <strong>Renewal alerts</strong>
            <span>See renewals early.</span>
          </div>
        </div>
      </section>

      <section className="auth-card">
        <div>
          <span className="eyebrow">Welcome back</span>
          <h2>Sign in to PulseFit</h2>
          <p className="muted-copy">
            Product admin: <strong>productadmin@pulsefit.com</strong> / <strong>1234</strong>
          </p>
          <p className="muted-copy">
            Gym owner demo: <strong>aarav@ironforge.com</strong> / <strong>1234</strong>
          </p>
          {IS_MOCK_API ? (
            <p className="muted-copy">Mock mode is enabled.</p>
          ) : null}
        </div>

        {message ? <div className="status-banner">{message}</div> : null}
        {error ? <div className="status-banner status-banner--error">{error}</div> : null}

        <form className="auth-form" onSubmit={handleLogin}>
          <label className="field">
            <span>Email</span>
            <input
              type="email"
              placeholder="productadmin@pulsefit.com"
              value={form.email}
              onChange={(event) => updateField("email", event.target.value)}
            />
          </label>

          <label className="field">
            <span>Password</span>
            <input
              type="password"
              placeholder="Enter your password"
              value={form.password}
              onChange={(event) => updateField("password", event.target.value)}
            />
          </label>

          <div className="auth-actions">
            <button className="button" type="submit" disabled={loading}>
              {loading ? "Signing in..." : "Login"}
            </button>
            {IS_DEMO_SEED_ENABLED ? (
              <button
                className="button button--ghost"
                type="button"
                onClick={handleSeed}
                disabled={seedLoading}
              >
                {seedLoading ? "Creating demo users..." : "Create demo users"}
              </button>
            ) : null}
          </div>
        </form>
      </section>
    </div>
  );
}
